import React, { useEffect, useMemo, useState } from 'react';
import { FiCalendar, FiCheckCircle, FiClock, FiLayers } from 'react-icons/fi';
import { Link } from 'react-router-dom';
import { bookingApi } from '../../api/bookingApi';
import LoadingSpinner from '../../components/common/LoadingSpinner';
import ErrorAlert from '../../components/common/ErrorAlert';

const UserDashboard = () => {
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    loadUserBookings();
  }, []);

  const loadUserBookings = async () => {
    try {
      setLoading(true);
      const data = await bookingApi.getUserBookings(1);
      setBookings(Array.isArray(data) ? data : []);
      setError(null);
    } catch (err) {
      setError('Failed to load user analytics');
    } finally {
      setLoading(false);
    }
  };

  const analytics = useMemo(() => {
    const total = bookings.length;
    const pending = bookings.filter((booking) => booking.status === 'PENDING').length;
    const approved = bookings.filter((booking) => booking.status === 'APPROVED').length;

    const totalHours = bookings.reduce((sum, booking) => {
      const start = new Date(booking.startTime).getTime();
      const end = new Date(booking.endTime).getTime();
      const durationHours = Math.max(0, end - start) / (1000 * 60 * 60);
      return sum + durationHours;
    }, 0);

    const usageByRoom = bookings.reduce((acc, booking) => {
      const key = booking.resourceName || 'Unknown Room';
      acc[key] = (acc[key] || 0) + 1;
      return acc;
    }, {});

    const topRooms = Object.entries(usageByRoom)
      .sort((a, b) => b[1] - a[1])
      .slice(0, 5)
      .map(([name, count]) => ({ name, count }));

    const upcoming = [...bookings]
      .filter((booking) => new Date(booking.startTime).getTime() >= Date.now())
      .sort((a, b) => new Date(a.startTime) - new Date(b.startTime))
      .slice(0, 5);

    return {
      total,
      pending,
      approved,
      totalHours: totalHours.toFixed(1),
      topRooms,
      upcoming,
    };
  }, [bookings]);

  const barWidth = (count) => {
    const maxCount = Math.max(...analytics.topRooms.map((item) => item.count), 1);
    return `${Math.round((count / maxCount) * 100)}%`;
  };

  const formatDateTime = (date) =>
    new Date(date).toLocaleString(undefined, {
      month: 'short',
      day: '2-digit',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
    });

  if (loading) return <LoadingSpinner />;
  if (error) return <ErrorAlert message={error} />;

  return (
    <div className="user-dashboard-page">
      <div className="booking-page-header">
        <div>
          <h1>User Dashboard</h1>
          <p>Track your booking activity and quick analytics.</p>
        </div>
        <Link to="/bookings/new" className="new-booking-btn">
          + New Booking
        </Link>
      </div>

      <div className="user-analytics-grid">
        <article className="user-analytics-card">
          <div className="analytics-icon blue"><FiCalendar /></div>
          <div>
            <p>Total Bookings</p>
            <h3>{analytics.total}</h3>
          </div>
        </article>

        <article className="user-analytics-card">
          <div className="analytics-icon amber"><FiClock /></div>
          <div>
            <p>Pending Requests</p>
            <h3>{analytics.pending}</h3>
          </div>
        </article>

        <article className="user-analytics-card">
          <div className="analytics-icon green"><FiCheckCircle /></div>
          <div>
            <p>Approved Bookings</p>
            <h3>{analytics.approved}</h3>
          </div>
        </article>

        <article className="user-analytics-card">
          <div className="analytics-icon slate"><FiLayers /></div>
          <div>
            <p>Hours Booked</p>
            <h3>{analytics.totalHours}</h3>
          </div>
        </article>
      </div>

      <div className="user-insights-grid">
        <section className="user-insight-card">
          <h4>Top Used Rooms</h4>
          {analytics.topRooms.length === 0 ? (
            <p className="no-data">No room usage yet.</p>
          ) : (
            <div className="usage-list">
              {analytics.topRooms.map((item) => (
                <div key={item.name} className="usage-row">
                  <div className="usage-row-head">
                    <span>{item.name}</span>
                    <strong>{item.count}</strong>
                  </div>
                  <div className="usage-bar-track">
                    <div className="usage-bar-fill" style={{ width: barWidth(item.count) }} />
                  </div>
                </div>
              ))}
            </div>
          )}
        </section>

        <section className="user-insight-card">
          <h4>Upcoming Bookings</h4>
          {analytics.upcoming.length === 0 ? (
            <p className="no-data">No upcoming bookings.</p>
          ) : (
            <ul className="upcoming-list">
              {analytics.upcoming.map((booking) => (
                <li key={booking.id}>
                  <div>
                    <strong>{booking.resourceName}</strong>
                    <small>{booking.purpose || 'No purpose provided'}</small>
                  </div>
                  <span>{formatDateTime(booking.startTime)}</span>
                </li>
              ))}
            </ul>
          )}
        </section>
      </div>
    </div>
  );
};

export default UserDashboard;
